// Generated by OrchestKit Claude Plugin
// Created: 2026-05-12

/**
 * Check Plugins Drift — PostToolUse/Write|Edit Hook
 *
 * M139 issue #1782 (C5 plugins/ drift detector).
 *
 * After a Write/Edit under `src/`, compare current build-input hashes
 * (`src/hooks/hooks.json` + `manifests/ork.json`) against the snapshot
 * captured at SessionStart by `plugins-drift-snapshot`. If they diverge
 * AND `plugins/` has not been touched in git since the snapshot, block
 * with a reminder to run `npm run build`.
 *
 * Why a block (not a notify):
 *   The drift CI check fails the PR later; surfacing this at Write time
 *   prevents a wasted push/CI roundtrip. `continueOnBlock: true` in
 *   hooks.json keeps the edit applied — only the next tool call is
 *   gated.
 *
 * Why time-window the snapshot:
 *   A stale snapshot from a long-running session would false-positive
 *   on rebases. Snapshots older than 1 hour are treated as missing.
 */

import { execFileSync } from 'node:child_process';
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { join, sep } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import {
  outputSilentSuccess,
  outputBlock,
  getField,
} from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import {
  buildSnapshot,
  sha256File,
  type PluginsDriftSnapshot,
} from '../lifecycle/plugins-drift-snapshot.js';

const HOOK_NAME = 'posttool/check-plugins-drift';
const SNAPSHOT_REL = join('.claude', 'state', 'plugins-snapshot.json');
const HOOKS_JSON_REL = join('src', 'hooks', 'hooks.json');
const MANIFEST_REL = join('manifests', 'ork.json');
const SNAPSHOT_MAX_AGE_MS = 60 * 60 * 1000; // 1 hour

const BLOCK_MESSAGE =
  '[plugins-drift] src/ edit detected but plugins/ has not been rebuilt this session.\n' +
  'Run: npm run build\n' +
  '(This would otherwise produce a plugins/ drift CI failure later.)';

/** True if a project-relative path lives under src/ (cross-platform). */
export function isSrcPath(projectDir: string, filePath: string): boolean {
  // Normalize both sides to absolute, then check prefix using OS separator.
  const abs = filePath.startsWith(projectDir) ? filePath : join(projectDir, filePath);
  const srcPrefix = projectDir.endsWith(sep)
    ? `${projectDir}src${sep}`
    : `${projectDir}${sep}src${sep}`;
  return abs.startsWith(srcPrefix);
}

/** Load the snapshot or return null if missing/stale/corrupt. */
export function loadSnapshot(projectDir: string): PluginsDriftSnapshot | null {
  const path = join(projectDir, SNAPSHOT_REL);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, 'utf8');
    const parsed = JSON.parse(raw) as PluginsDriftSnapshot;
    if (!parsed.at || typeof parsed.hooks_json_hash !== 'string') return null;
    const age = Date.now() - new Date(parsed.at).getTime();
    if (Number.isNaN(age) || age > SNAPSHOT_MAX_AGE_MS) return null;
    return parsed;
  } catch {
    return null;
  }
}

/**
 * Has `plugins/` been touched in any commit since `sinceIso`?
 * Returns false on git failure (treat as "no rebuild evidence").
 */
export function pluginsTouchedSince(projectDir: string, sinceIso: string): boolean {
  try {
    const out = execFileSync(
      'git',
      ['-C', projectDir, 'log', `--since=${sinceIso}`, '--name-only', '--pretty=format:', '--', 'plugins/'],
      { encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] },
    );
    return out.trim().length > 0;
  } catch {
    return false;
  }
}

/**
 * Is `plugins/` dirty in the working tree right now?
 *
 * `npm run build` rewrites plugins/ WITHOUT committing, so commit history
 * alone misses an in-session rebuild — the hook then re-blocks every src/
 * edit until something touching plugins/ is committed (observed after a
 * branch switch mid-session: snapshot hashes from the old branch never
 * match, and the rebuild evidence never appears). Uncommitted plugins/
 * changes count as rebuild evidence; the snapshot refresh re-baselines
 * hashes, so a later src/ edit still re-arms the check.
 * Returns false on git failure (treat as "no rebuild evidence").
 */
export function pluginsDirtyNow(projectDir: string): boolean {
  try {
    const out = execFileSync(
      'git',
      ['-C', projectDir, 'status', '--porcelain', '--', 'plugins/'],
      { encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] },
    );
    return out.trim().length > 0;
  } catch {
    return false;
  }
}

export function checkPluginsDrift(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const toolName = input.tool_name || '';
  if (toolName !== 'Write' && toolName !== 'Edit' && toolName !== 'MultiEdit') {
    return outputSilentSuccess();
  }

  const filePath = getField<string>(input, 'tool_input.file_path') || '';
  if (!filePath) return outputSilentSuccess();
  if (!isSrcPath(ctx.projectDir, filePath)) return outputSilentSuccess();

  const snapshot = loadSnapshot(ctx.projectDir);
  if (!snapshot) return outputSilentSuccess();

  const currentHooks = sha256File(join(ctx.projectDir, HOOKS_JSON_REL));
  const currentManifest = sha256File(join(ctx.projectDir, MANIFEST_REL));

  const hooksChanged =
    !!snapshot.hooks_json_hash && currentHooks !== snapshot.hooks_json_hash;
  const manifestChanged =
    !!snapshot.manifest_hash && currentManifest !== snapshot.manifest_hash;

  if (!hooksChanged && !manifestChanged) {
    return outputSilentSuccess();
  }

  // Build inputs changed — has plugins/ been rebuilt since snapshot?
  // Evidence: a commit touching plugins/ OR uncommitted plugins/ changes
  // (npm run build rewrites the working tree without committing).
  if (pluginsTouchedSince(ctx.projectDir, snapshot.at) || pluginsDirtyNow(ctx.projectDir)) {
    // Treat as "already rebuilt": refresh snapshot so we don't re-fire.
    try {
      const refreshed = buildSnapshot(ctx.projectDir);
      writeFileSync(
        join(ctx.projectDir, SNAPSHOT_REL),
        JSON.stringify(refreshed, null, 2),
      );
      ctx.log(HOOK_NAME, 'plugins/ rebuilt since snapshot — refreshed');
    } catch {
      /* ignore */
    }
    return outputSilentSuccess();
  }

  ctx.log(
    HOOK_NAME,
    `drift detected: hooks=${hooksChanged} manifest=${manifestChanged} file=${filePath}`,
  );
  return outputBlock(BLOCK_MESSAGE);
}
